document.getElementById("imageUpload")?.addEventListener("change",event=>{const file=event.target.files?.[0];if(!file)return;if(file.size>3500000){alert("Das Bild ist zu groß. Bitte maximal 3,5 MB verwenden.");return}const reader=new FileReader();reader.onload=()=>{const p=ap(),item=p.illustrations.items.find(x=>x.id===activeIllustrationId);item.imageData=reader.result;item.imageName=file.name;item.status="image-added";if(p.layout)L.sync(p);patch(p);render();U.toast("Bild hinzugefügt und Probebuch aktualisiert")};reader.readAsDataURL(file)});
